std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a buffer_adaptor object from the source buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> adaptor(source_buffer);

    // Check if the requested bytes are available in the buffer
    if (bytes_to_read > adaptor.size()) {
        // Handle error appropriately - return empty vector if not enough data
        return {};
    }

    // Use the read() method to copy data from the buffer_adaptor to the destination
    std::vector<uint8_t> destination(bytes_to_read);
    adaptor.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a buffer_adaptor object from the destination buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(dest_buffer);

    // Check if there's enough space in the buffer for the source data
    if (source_data.size() > adaptor.free()) {
        // Handle error appropriately - resize buffer if needed
        dest_buffer.resize(dest_buffer.size() + source_data.size());
        // Recreate adaptor with resized buffer
        adaptor = hexi::buffer_adaptor<std::vector<uint8_t>>(dest_buffer);
    }

    // Use the write() method to copy data from the source to the buffer_adaptor
    adaptor.write(source_data.data(), source_data.size());
}
