    // Allocate all blocks (exhausting the free list)
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate();
    }
    // All blocks are removed from the free list via pop()

    // Deallocate all blocks (returning them to the free list)
    for (size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(blocks[i]);
    }
    // All blocks are added back to the free list via push(), maintaining LIFO order

    // Demonstrate that deallocated blocks are available for reallocation
    std::uint64_t* new_block = allocator.allocate();
    // This block comes from the free list (not from new allocation)
    allocator.deallocate(new_block);

    // The free list continues to manage memory efficiently through push() and pop()
}

