    hexi::file_buffer buffer(file_path);

    if (!buffer || bytes_to_preview > buffer.size()) {
        return {}; // Return empty vector on error or insufficient data
    }

    std::vector<uint8_t> preview_data(bytes_to_preview);
    buffer.copy(preview_data.data(), bytes_to_preview);

    if (buffer.error()) {
        return {}; // Return empty vector on copy error
