    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(non_const_buffer, hexi::init_empty_t{});

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor, buffer.size());

    // Deserialize message_id with big-endian conversion
    uint32_t message_id;
    stream.read(&message_id);
    message_id = hexi::endian::big_to_native(message_id);
    packet.message_id = message_id;

    // Deserialize data_values vector count
    uint32_t count;
    stream.read(&count);
    count = hexi::endian::big_to_native(count);

    // Resize the vector and read the container
    packet.data_values.resize(count);
    stream.read_container(packet.data_values);

    // Convert each element from big-endian to native
    for (auto& val : packet.data_values) {
        val = hexi::endian::big_to_native(val);
    }

    // Deserialize checksum with big-endian conversion
    uint32_t checksum;
    stream.read(&checksum);
    checksum = hexi::endian::big_to_native(checksum);
    packet.checksum = checksum;

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header;

    // Create a buffer adaptor for the input buffer
    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(non_const_buffer, hexi::init_empty_t{});

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor, buffer.size());

    // Use span to get a zero-copy view of the first 4 bytes (message_id)
    auto message_id_span = stream.span<uint32_t>(1);
    header.message_id = *message_id_span;

    // Convert from big-endian to native
    header.message_id = hexi::endian::big_to_native(header.message_id);

    // Use skip to advance past the header (4 bytes)
    stream.skip(4);

    return header;
}

